import React from "react";
import ListItem from "./ListItem";

const List = ({ list, head, type }) => {
  return (
    <section>
      <h3 className="head">{head}</h3>
      <article className="list">
        {list &&
          list.map((x, index) => <ListItem key={index} item={x} type={type} />)}
      </article>
    </section>
  );
};

export default List;
