import React, { useState } from "react";
import { BsFillStarFill } from "react-icons/bs";
import { FaHeart } from "react-icons/fa";
import { Link } from "react-router-dom";

const ListItem = ({ item, type }) => {
  const [favorite, setFavorite] = useState(true);
  const {
    backdrop_path,
    id,
    title,
    release_date,
    poster_path,
    vote_average,
    overview,
    genre_ids,
    name,
    first_air_date,
  } = item;

  return (
    <Link to={`/${type}/${id}`} className="list-item">
      <img
        src={"https://image.tmdb.org/t/p/w200" + poster_path}
        alt="No Image"
      />
      <div className="item-detail">
        <FaHeart
          color="red"
          size="20"
          style={{
            position: "absolute",
            marginTop: "-40px",
            marginLeft: "105px",
            color: favorite ? "red" : "grey",
            // zIndex: "2",
          }}
        />
        <h6>
          {title && title.length > 15 ? title.substr(0, 15) + "..." : title}
        </h6>
        <h6>{name && name.length > 15 ? name.substr(0, 15) + "..." : name}</h6>
        <div className="details">
          <BsFillStarFill
            color="gold"
            fontSize=".8rem"
            style={{
              position: "relative",
              marginTop: "-5px",
            }}
          />
          <span style={{ marginLeft: "5px" }}>{vote_average.toFixed(1)}</span>
          &emsp;&emsp;
          <span>{release_date && release_date.substr(0, 4)}</span>
          <span>{first_air_date && first_air_date.substr(0, 4)}</span>
        </div>
      </div>
    </Link>
  );
};

export default ListItem;
