import React from "react";
import Search from "./Search";
import { Navbar, Nav, Container } from "react-bootstrap";
import { Link } from "react-router-dom";

const Header = () => {
  return (
    <Navbar expand="lg" variant="dark">
      <Navbar.Brand as={Link} to="/" className="ms-5">
        {/* <img src={logo} style={icon} className="icon" href="#" /> */}
        <span>movieDB v3</span>
      </Navbar.Brand>
      <Navbar.Toggle aria-controls="basic-navbar-nav" />
      <Navbar.Collapse
        id="basic-navbar-nav"
        className=""
        style={{ flexGrow: "0", flexBasis: "100%" }}
      >
        <Search />
        <Nav
          style={{
            fontSize: "1.2em",
            color: "color: #d6dcff",
            // float: "right",
          }}
          className="me-5"
        >
          <Nav.Link as={Link} to="/genres/movie" className="">
            Movies
          </Nav.Link>
          <Nav.Link as={Link} to="/genres/tv" className="">
            TV Shows
          </Nav.Link>
          <Nav.Link as={Link} to="/" className="">
            Login
          </Nav.Link>
        </Nav>
      </Navbar.Collapse>
    </Navbar>
  );
};

export default Header;
